"Initial BPH Diagnosis Starts Within 6 Months Before the Measurement Period" AS (
SELECT p.patient_id, (SELECT resource FROM (SELECT patient_id, resource FROM "Condition: Benign prostatic hyperplasia with lower urinary tract symptoms (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Benign prostatic hyperplasia with lower urinary tract symptoms (qicore-condition-encounter-diagnosis)") AS NewBPHDiagnosis WHERE intervalContains(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE), intervalStart(CASE WHEN fhirpath_text(NewBPHDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(NewBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NewBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NewBPHDiagnosis.resource, 'recordedDate')), fhirpath_text(NewBPHDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(NewBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NewBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NewBPHDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(NewBPHDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(NewBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NewBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NewBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(NewBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NewBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NewBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AND (fhirpath_bool(NewBPHDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(NewBPHDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(NewBPHDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(NewBPHDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND NewBPHDiagnosis.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(NewBPHDiagnosis.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(NewBPHDiagnosis.resource, 'onset')), '{') THEN fhirpath_text(NewBPHDiagnosis.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(NewBPHDiagnosis.resource, 'onset'), fhirpath_text(NewBPHDiagnosis.resource, 'onset'), TRUE, TRUE) END) ASC NULLS LAST, json_extract_string(NewBPHDiagnosis.resource, '$.id') ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
