SELECT p.patient_id, (SELECT resource FROM "Initial BPH Diagnosis Starts Within 6 Months Before the Measurement Period" AS InitialBPHDiagnosis WHERE EXISTS (SELECT 1 FROM "Encounter: Hospital Services for Urology Care" AS UrologyHospitalServices WHERE intervalContains(intervalFromBounds(CAST(intervalStart(fhirpath_text(UrologyHospitalServices.resource, 'period')) AS VARCHAR), CAST(dateAddQuantity(CAST(intervalEnd(fhirpath_text(UrologyHospitalServices.resource, 'period')) AS VARCHAR), '{"value": 31.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE), intervalStart(CASE WHEN fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(InitialBPHDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AND fhirpath_text(UrologyHospitalServices.resource, 'status') = 'finished' AND UrologyHospitalServices.patient_id = InitialBPHDiagnosis.patient_id) AND InitialBPHDiagnosis.patient_id = p.patient_id LIMIT 1) AS resource FROM _patients AS p
),
"Has Qualifying BPH Diagnosis" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Initial BPH Diagnosis Starts Within 6 Months Before the Measurement Period" AS j1 ON j1.patient_id = p.patient_id WHERE j1.resource IS NOT NULL
),
"Patient is Male" AS (
SELECT p.patient_id FROM _patients AS p WHERE fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'gender') = 'male'
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Patient is Male" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Has Qualifying Encounter" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Has Qualifying BPH Diagnosis" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
),
"Urinary Retention Diagnosis Starts Within 1 Year After Initial BPH Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Urinary Retention (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Urinary Retention (qicore-condition-encounter-diagnosis)") AS UrinaryRetention WHERE (fhirpath_bool(UrinaryRetention.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(UrinaryRetention.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(UrinaryRetention.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(UrinaryRetention.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "Initial BPH Diagnosis Starts Within 6 Months Before the Measurement Period") AS InitialBPHDiagnosis WHERE CAST(CAST(intervalStart(CASE WHEN fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(InitialBPHDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(UrinaryRetention.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')), fhirpath_text(UrinaryRetention.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(UrinaryRetention.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(UrinaryRetention.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')), fhirpath_text(UrinaryRetention.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(UrinaryRetention.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(UrinaryRetention.resource, 'onsetDateTime'), fhirpath_text(UrinaryRetention.resource, 'onsetPeriod.start'), fhirpath_text(UrinaryRetention.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= CAST(CAST(intervalStart(CASE WHEN fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(InitialBPHDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) + INTERVAL '1 year' AS DATE) AND InitialBPHDiagnosis.patient_id = UrinaryRetention.patient_id)
),
"Urinary Symptom Score Assessment" AS (
(SELECT patient_id, resource FROM "Documented IPSS Assessment Result") UNION (SELECT patient_id, resource FROM "AUA Symptom Index and Quality of Life Assessment Result")
),
"Urinary Symptom Score 6 to 12 Months After Initial BPH Diagnosis" AS (
SELECT p.patient_id, (SELECT resource FROM "Urinary Symptom Score Assessment" AS USSAssessment WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Initial BPH Diagnosis Starts Within 6 Months Before the Measurement Period") AS InitialBPHDiagnosis WHERE MonthsBetween(intervalStart(CASE WHEN fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(InitialBPHDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END), fhirpath_text(USSAssessment.resource, 'effectiveDatetime')) BETWEEN 6 AND 12 AND InitialBPHDiagnosis.patient_id = USSAssessment.patient_id) AND USSAssessment.patient_id = p.patient_id ORDER BY fhirpath_text(USSAssessment.resource, 'effectiveDatetime') DESC NULLS FIRST, json_extract_string(USSAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
"BMI Exam Result Greater Than or Equal To 40 During Measurement Period and On or Before Follow Up USS Assessment" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT CASE WHEN NOT (intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) END FROM "Observation (us-core-bmi)" AS BMIExam WHERE BMIExam.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Urinary Symptom Score 6 to 12 Months After Initial BPH Diagnosis") AS FollowUpUSSAssessment WHERE TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'value')), '{') THEN json_extract_string(fhirpath_text(BMIExam.resource, 'value'), '$.value') ELSE fhirpath_text(BMIExam.resource, 'value') END AS DOUBLE) >= 40.0 AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(BMIExam.resource, 'status')) AND CAST(CASE WHEN NOT (intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) END AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(CASE WHEN NOT (intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) END AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND CAST(CASE WHEN NOT (intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN fhirpath_text(BMIExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BMIExam.resource, 'effective')), '{') THEN fhirpath_text(BMIExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BMIExam.resource, 'effective'), fhirpath_text(BMIExam.resource, 'effective'), TRUE, TRUE) END) END AS TIMESTAMP) <= CAST(fhirpath_text(FollowUpUSSAssessment.resource, 'effectiveDatetime') AS TIMESTAMP) AND FollowUpUSSAssessment.patient_id = BMIExam.patient_id))
),
"Morbid Obesity Diagnosis On or Before Follow Up USS Assessment" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Morbid Obesity (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Morbid Obesity (qicore-condition-encounter-diagnosis)") AS MorbidObesityDiagnosis WHERE (fhirpath_bool(MorbidObesityDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(MorbidObesityDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(MorbidObesityDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(MorbidObesityDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "Urinary Symptom Score 6 to 12 Months After Initial BPH Diagnosis") AS FollowUpUSSAssessment WHERE intervalOverlaps(CASE WHEN fhirpath_text(MorbidObesityDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')), fhirpath_text(MorbidObesityDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MorbidObesityDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AND CAST(intervalStart(CASE WHEN fhirpath_text(MorbidObesityDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')), fhirpath_text(MorbidObesityDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MorbidObesityDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetDateTime'), fhirpath_text(MorbidObesityDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(MorbidObesityDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= CAST(fhirpath_text(FollowUpUSSAssessment.resource, 'effectiveDatetime') AS DATE) AND FollowUpUSSAssessment.patient_id = MorbidObesityDiagnosis.patient_id)
),
"Morbid Obesity Diagnosis or BMI Exam Result Greater Than or Equal to 40 Starts On or Before Follow Up USS Assessment" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Morbid Obesity Diagnosis On or Before Follow Up USS Assessment" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "BMI Exam Result Greater Than or Equal To 40 During Measurement Period and On or Before Follow Up USS Assessment" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Has Initial BPH Diagnosis Starts During or Within 30 Days After End of Hospitalization" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT 1 FROM "Urinary Retention Diagnosis Starts Within 1 Year After Initial BPH Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR j1.resource IS NOT NULL OR EXISTS (SELECT 1 FROM "Morbid Obesity Diagnosis or BMI Exam Result Greater Than or Equal to 40 Starts On or Before Follow Up USS Assessment" AS sub WHERE sub.patient_id = p.patient_id)
),
"Urinary Symptom Score Within 1 Month After Initial BPH Diagnosis" AS (
SELECT p.patient_id, (SELECT resource FROM "Urinary Symptom Score Assessment" AS USSAssessment WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Initial BPH Diagnosis Starts Within 6 Months Before the Measurement Period") AS InitialBPHDiagnosis WHERE CAST(intervalStart(CASE WHEN fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(InitialBPHDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= CAST(fhirpath_text(USSAssessment.resource, 'effectiveDatetime') AS DATE) AND CAST(fhirpath_text(USSAssessment.resource, 'effectiveDatetime') AS DATE) <= CAST(intervalStart(CASE WHEN fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), fhirpath_text(InitialBPHDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(InitialBPHDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(InitialBPHDiagnosis.resource, 'onsetDateTime'), fhirpath_text(InitialBPHDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(InitialBPHDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) + INTERVAL '1 month' AND InitialBPHDiagnosis.patient_id = USSAssessment.patient_id) AND USSAssessment.patient_id = p.patient_id ORDER BY fhirpath_text(USSAssessment.resource, 'effectiveDatetime') ASC NULLS LAST, json_extract_string(USSAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
"Denominator" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Urinary Symptom Score Within 1 Month After Initial BPH Diagnosis" AS j1 ON j1.patient_id = p.patient_id LEFT JOIN "Urinary Symptom Score 6 to 12 Months After Initial BPH Diagnosis" AS j2 ON j2.patient_id = p.patient_id WHERE EXISTS (SELECT 1 FROM "Initial Population" AS sub WHERE sub.patient_id = p.patient_id) AND j1.resource IS NOT NULL AND j2.resource IS NOT NULL
),
"Urinary Symptom Score Change" AS (
SELECT FirstUSSAssessment.patient_id, CAST(TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(FirstUSSAssessment.resource, 'valueInteger')), '{') THEN json_extract_string(fhirpath_text(FirstUSSAssessment.resource, 'valueInteger'), '$.value') ELSE fhirpath_text(FirstUSSAssessment.resource, 'valueInteger') END AS DOUBLE) - TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(FollowUpUSSAssessment.resource, 'valueInteger')), '{') THEN json_extract_string(fhirpath_text(FollowUpUSSAssessment.resource, 'valueInteger'), '$.value') ELSE fhirpath_text(FollowUpUSSAssessment.resource, 'valueInteger') END AS DOUBLE) AS VARCHAR) AS resource FROM "Urinary Symptom Score Within 1 Month After Initial BPH Diagnosis" AS FirstUSSAssessment CROSS JOIN (SELECT * FROM "Urinary Symptom Score 6 to 12 Months After Initial BPH Diagnosis") AS FollowUpUSSAssessment WHERE FollowUpUSSAssessment.patient_id = FirstUSSAssessment.patient_id
),
"Urinary Symptom Score Improvement Greater Than or Equal To 3" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Urinary Symptom Score Change" AS USSImprovement WHERE USSImprovement.patient_id = p.patient_id AND TRY_CAST(USSImprovement.resource AS DOUBLE) >= 3 LIMIT 1)
),
"Numerator" AS (
SELECT * FROM "Urinary Symptom Score Improvement Greater Than or Equal To 3"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
